const express = require('express');
const router = express.Router();

const processedTransactions = new Set();

function isValidCardNumber(cardNumber) {
  if (!cardNumber || typeof cardNumber !== 'string') return false;
  if (!/^\d{13,19}$/.test(cardNumber)) return false;
  let sum = 0;
  let isEven = false;
  for (let i = cardNumber.length - 1; i >= 0; i--) {
    let digit = parseInt(cardNumber[i]);
    if (isEven) {
      digit *= 2;
      if (digit > 9) digit -= 9;
    }
    sum += digit;
    isEven = !isEven;
  }
  return sum % 10 === 0;
}

function isValidAmount(amount) {
  return typeof amount === 'number' && amount > 0 && amount < 1000000;
}

router.post('/payment', async (req, res) => {
  const {cardNumber, amount, transactionId} = req.body;

  if (!isValidCardNumber(cardNumber)) {
    return res.status(400).json({error: 'Invalid card number'});
  }

  if (!isValidAmount(amount)) {
    return res.status(400).json({error: 'Invalid amount'});
  }

  // Check for duplicate transactions
  if (transactionId && processedTransactions.has(transactionId)) {
    return res.status(409).json({error: 'Duplicate transaction'});
  }

  const txnId = transactionId || generateTransactionId();
  processedTransactions.add(txnId);

  const result = {
    success: true,
    transactionId: txnId,
    amount: amount
  };

  res.status(200).json(result);
});

function generateTransactionId() {
  return 'TXN-' + Date.now() + '-' + Math.random().toString(36).substr(2, 9);
}

module.exports = router;
